
import sys

# 设置新的限制（至少 6951，可根据实际需求调整）
sys.set_int_max_str_digits(10000)  # 这里设为 10000 位，足够处理 6951 位的数字

# 现在可以安全转换超长数字字符串了
long_num_str = "123456"  # 你的 6951 位数字字符串
num = int(long_num_str)  # 不会报错

def main(n):
    # 根据规模 n 生成测试数据（示例：m = n, k = 2*n）
    m = n
    k = 2 * n

    res = m ^ k
    s = bin(res)[2:]  # 去掉 '0b' 前缀
    s_int = int(s) if s else 0

    if s_int == 0:
        print(0)
    else:
        length = len(str(s_int))
        ans = (2 ** length) - 1
        print(ans)


if __name__ == "__main__":
    # 示例：调用 main(10)000000000
    main()